css:
.loader {color: var(--loader-color, #0284c7);
  --loader-secondary-color: #7dd3fc;
  --loader-bg: #ffffff;
   width: 80px;
   height: 40px;
   background: var(--loader-color, #0284c7);
   position: relative;
   overflow: hidden;
   animation: l9-0 1.5s infinite steps(10);
}
.loader:before, .loader:after {
  content: "";
   position: absolute;
   inset: -50%;
   --rad: radial-gradient(1px 4px,var(--loader-secondary-color, #7dd3fc) 92%,#0000);
   background: var(--rad) 20% 0, var(--rad) 70% 7%;
   background-size: var(--w,20px) var(--h,18px);
   animation: l9-1 0.2s linear infinite;
   transform: skew(-10deg);
}
.loader:after  {
  --h: 12px;
   --w: 16px;
   animation-duration: 0.3s;
}
@keyframes l9-0 {
  0%,15%,20%,30%,100% {background:var(--loader-color, #0284c7)}
10%,22% {background:var(--loader-secondary-color, #7dd3fc)}
}
@keyframes l9-1 {
  100% {transform:skew(-10deg) translateY(var(--h,18px))}
}
